function norm(s: string | null | undefined): string {
  return (s ?? '').toLowerCase().replace(/[^a-z0-9]/g, '')
}

/** Find a circuit by OpenF1 short name / location (best-effort, normalised). */
export function findCircuit(...names: (string | null | undefined)[]): CircuitOutline | null {
  for (const n of names) {
    const key = norm(n)
    if (!key) continue
    const id = ALIASES[key]
    if (id) return CIRCUITS[id]
  }
  return null
}
